//! Hope Jar Tiered Selector — dispatches to the appropriate ADE tier.
//!
//! Selects between E_6, E_7, E_8, and Leech tiers based on memory budget
//! and throughput target.
//!
//! Tiers (capacity ascending):
//!   - E_6:   51,840 keys       (12×72×60)     — use for <64 KB budget
//!   - E_7:   2,903,040 keys    (18×126×1280)  — use for 64–512 KB
//!   - E_8:   696,729,600 keys  (30×240×96768) — use for 512 KB–5 MB (default)
//!   - Leech: 2,090,188,800 keys (30×720×96768) — use for ≥5 MB (unconstrained)

use crate::hope_jar::BoxState;
use crate::hope_jar_e6::{self as e6, HopeJarE6};
use crate::hope_jar_e7::{self as e7, HopeJarE7};
use crate::hope_jar_e8::{self as e8, HopeJarE8};
use crate::hope_jar_leech::{self as leech, HopeJarLeech};
use crate::hope_jar_kaiju::{self as kaiju, HopeJarKaiju};

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum HopeTier {
    E6,
    E7,
    E8,
    Leech,
    Kaiju,
}

impl HopeTier {
    /// Select tier based on memory budget (KB).
    pub fn from_budget(budget_kb: usize) -> Self {
        match budget_kb {
            0..=64 => HopeTier::E6,
            65..=512 => HopeTier::E7,
            513..=5_000 => HopeTier::E8,
            5_001..=50_000 => HopeTier::Leech,
            _ => HopeTier::Kaiju,
        }
    }

    pub fn capacity(&self) -> u64 {
        match self {
            HopeTier::E6 => e6::E6_WEYL_ORDER,
            HopeTier::E7 => e7::E7_WEYL_ORDER,
            HopeTier::E8 => e8::E8_WEYL_ORDER,
            HopeTier::Leech => leech::LEECH_TIER_CAPACITY,
            HopeTier::Kaiju => kaiju::KAIJU_TIER_CAPACITY,
        }
    }

    pub fn disk_footprint_kb(&self) -> usize {
        match self {
            HopeTier::E6 => 4,     // ~3 KB
            HopeTier::E7 => 5,     // ~4.5 KB
            HopeTier::E8 => 4,     // ~3.3 KB
            HopeTier::Leech => 10, // ~10 KB
            HopeTier::Kaiju => 12, // ~12 KB (latent |Co0| field, seeds only)
        }
    }
}

impl std::fmt::Display for HopeTier {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            HopeTier::E6 => write!(f, "E6"),
            HopeTier::E7 => write!(f, "E7"),
            HopeTier::E8 => write!(f, "E8"),
            HopeTier::Leech => write!(f, "Leech"),
            HopeTier::Kaiju => write!(f, "Kaiju"),
        }
    }
}

/// Hope Jar Tier Selector: wraps one jar per tier, dispatches to the selected tier.
pub struct HopeTierSelector {
    tier: HopeTier,
    e6: HopeJarE6,
    e7: HopeJarE7,
    e8: HopeJarE8,
    leech: HopeJarLeech,
    kaiju: HopeJarKaiju,
}

impl HopeTierSelector {
    pub fn new(tier: HopeTier) -> Self {
        Self {
            tier,
            e6: HopeJarE6::new(),
            e7: HopeJarE7::new(),
            e8: HopeJarE8::new(),
            leech: HopeJarLeech::new(),
            kaiju: HopeJarKaiju::new(),
        }
    }

    pub fn from_budget(budget_kb: usize) -> Self {
        Self::new(HopeTier::from_budget(budget_kb))
    }

    pub fn tier(&self) -> HopeTier {
        self.tier
    }

    pub fn select_tier(&mut self, budget_kb: usize) {
        self.tier = HopeTier::from_budget(budget_kb);
    }

    pub fn capacity(&self) -> u64 {
        self.tier.capacity()
    }

    /// Charge the active jar from standing-wave seeds.
    pub fn charge_from_seeds(&mut self, seeds: &[u64], analysis_time_us: u64) {
        match self.tier {
            HopeTier::E6 => self.e6.charge_from_seeds(seeds, analysis_time_us),
            HopeTier::E7 => self.e7.charge_from_seeds(seeds, analysis_time_us),
            HopeTier::E8 => self.e8.charge_from_seeds(seeds, analysis_time_us),
            HopeTier::Leech => self.leech.charge_from_seeds(seeds, analysis_time_us),
            HopeTier::Kaiju => self.kaiju.charge_from_seeds(seeds, analysis_time_us),
        }
    }

    /// Predict a single key for a shape hash (O(1) point query).
    pub fn predict(&self, shape_hash: u64) -> u64 {
        match self.tier {
            HopeTier::E6 => self.e6.predict(shape_hash),
            HopeTier::E7 => self.e7.predict(shape_hash),
            HopeTier::E8 => self.e8.predict(shape_hash),
            HopeTier::Leech => self.leech.predict(shape_hash),
            HopeTier::Kaiju => self.kaiju.predict(shape_hash),
        }
    }

    /// Is the active jar sealed?
    pub fn is_sealed(&self) -> bool {
        match self.tier {
            HopeTier::E6 => self.e6.is_sealed(),
            HopeTier::E7 => self.e7.is_sealed(),
            HopeTier::E8 => self.e8.is_sealed(),
            HopeTier::Leech => self.leech.is_sealed(),
            HopeTier::Kaiju => self.kaiju.is_sealed(),
        }
    }

    /// Get state of the active jar.
    pub fn state(&self) -> BoxState {
        match self.tier {
            HopeTier::E6 => self.e6.state(),
            HopeTier::E7 => self.e7.state(),
            HopeTier::E8 => self.e8.state(),
            HopeTier::Leech => self.leech.state(),
            HopeTier::Kaiju => self.kaiju.state(),
        }
    }

    /// Get telemetry for the active jar.
    pub fn telemetry(&self) -> String {
        match self.tier {
            HopeTier::E6 => format!("{}", self.e6.telemetry()),
            HopeTier::E7 => format!("{}", self.e7.telemetry()),
            HopeTier::E8 => format!("{}", self.e8.telemetry()),
            HopeTier::Leech => format!("{}", self.leech.telemetry()),
            HopeTier::Kaiju => format!("HopeJarKaiju[{:?}] seeds={} cap={}", self.kaiju.state(), self.kaiju.seeds_loaded(), self.kaiju.capacity()),
        }
    }
}

impl Default for HopeTierSelector {
    fn default() -> Self {
        Self::new(HopeTier::E8) // E8 is the standard tier
    }
}

impl std::fmt::Debug for HopeTierSelector {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("HopeTierSelector")
            .field("tier", &self.tier)
            .field("capacity", &self.capacity())
            .finish()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn rain_seeds() -> Vec<u64> {
        (0..170u64)
            .map(|i| i.wrapping_mul(2654435761).wrapping_add(1))
            .collect()
    }

    #[test]
    fn test_tier_selection_by_budget() {
        assert_eq!(HopeTier::from_budget(32), HopeTier::E6);
        assert_eq!(HopeTier::from_budget(100), HopeTier::E7);
        assert_eq!(HopeTier::from_budget(1_000), HopeTier::E8);
        assert_eq!(HopeTier::from_budget(10_000), HopeTier::Leech);
    }

    #[test]
    fn test_tier_capacity_ordering() {
        assert!(HopeTier::E6.capacity() < HopeTier::E7.capacity());
        assert!(HopeTier::E7.capacity() < HopeTier::E8.capacity());
        assert!(HopeTier::E8.capacity() < HopeTier::Leech.capacity());
    }

    #[test]
    fn test_selector_dispatches_e6() {
        let mut sel = HopeTierSelector::new(HopeTier::E6);
        let seeds = rain_seeds();
        sel.charge_from_seeds(&seeds, 1000);
        assert!(sel.is_sealed());
        let key = sel.predict(12345);
        assert_ne!(key, 0);
    }

    #[test]
    fn test_selector_dispatches_e7() {
        let mut sel = HopeTierSelector::new(HopeTier::E7);
        let seeds = rain_seeds();
        sel.charge_from_seeds(&seeds, 1000);
        assert!(sel.is_sealed());
        let key = sel.predict(12345);
        assert_ne!(key, 0);
    }

    #[test]
    fn test_selector_dispatches_leech() {
        let mut sel = HopeTierSelector::new(HopeTier::Leech);
        let seeds = rain_seeds();
        sel.charge_from_seeds(&seeds, 1000);
        assert!(sel.is_sealed());
        let key = sel.predict(12345);
        assert_ne!(key, 0);
    }

    #[test]
    fn test_selector_tier_switch() {
        let mut sel = HopeTierSelector::default(); // starts as E8
        assert_eq!(sel.tier(), HopeTier::E8);
        sel.select_tier(100); // switch to E7
        assert_eq!(sel.tier(), HopeTier::E7);
        sel.select_tier(10_000); // switch to Leech
        assert_eq!(sel.tier(), HopeTier::Leech);
    }
}
